from sklearn.cluster import KMeans

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(point1, point2):
        return np.sqrt(np.sum((np.array(point1) - np.array(point2)) ** 2))

    def calculate_arrival_time(start_pos, end_pos):
        return current_time + (euclidean_distance(start_pos, end_pos) / truck_speed)

    num_clusters = min(5, len(unvisited_customers))  # Maximum 5 clusters or total number of customers if less.
    if num_clusters <= 0:
        return None

    kmeans = KMeans(n_clusters=num_clusters)
    customer_positions = np.array(unvisited_customers)
    labels = kmeans.fit_predict(customer_positions)

    cluster_centers = kmeans.cluster_centers_

    best_node = None
    lowest_cost = float('inf')

    for cluster_index in range(num_clusters):
        cluster_members = customer_positions[labels == cluster_index]
        cluster_time_windows = np.array(time_windows)[labels == cluster_index]

        cluster_center = cluster_centers[cluster_index]
        center_arrival_time = calculate_arrival_time(cur_truck_pos, cluster_center)

        for i, member in enumerate(cluster_members):
            member_index = np.where(np.all(customer_positions == member, axis=1))[0][0]
            arrival_time = calculate_arrival_time(cur_truck_pos, member)
            start_window, end_window = cluster_time_windows[i]

            if arrival_time < start_window:
                penalty = (start_window - arrival_time) * 2  # Weight waiting time less
            elif arrival_time > end_window:
                penalty = (arrival_time - end_window) * 10  # Heavy penalty for missing window
            else:
                penalty = 0

            cost = euclidean_distance(cur_truck_pos, member) + penalty

            if cost < lowest_cost:
                lowest_cost = cost
                best_node = member_index

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(from_pos, to_pos, speed):
        distance = np.linalg.norm(from_pos - to_pos)
        return distance / speed

    def calculate_urgency_penalty(time_now, time_window):
        end_time = time_window[1]
        if time_now > end_time:
            return float('inf')  # Extremely high penalty if past the end of the window
        else:
            return end_time - time_now

    best_node = None
    min_cost = float('inf')

    for idx, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos, truck_speed)
        arrival_time = current_time + travel_time
        urgency_penalty = calculate_urgency_penalty(arrival_time, time_windows[idx])

        cost = travel_time + urgency_penalty

        if cost < min_cost:
            min_cost = cost
            best_node = idx

    return best_node
